package rocket {
    requirement def Thrusters {
        doc /* The rocket shall have 2 thrusters. */
    }

    part def Fuel;

    part def Rocket {
        doc /* A vehicle designed to propel itself by expelling exhaust gas. */

        part thrusters : Thrusters[2];
        part fuel : Fuel;

        attribute maxSpeed : Real;
        attribute range : Real;
    }
}

package rocket {
    requirement def Thrusters {
        doc /* The rocket shall have 2 thrusters. */
    }

    requirement thrusterCountRequirement : Thrusters;

    part def Rocket {
        doc /* A vehicle designed to propel itself by expelling exhaust gas. */

        part thrusters : Thrusters[2] {
            doc /* Resolved to 2 instances to satisfy thrusterCountRequirement; requirement takes precedence over the previous conflicting multiplicity of 3. */
        }
        part fuel : Fuel;

        attribute maxSpeed : Real;
        attribute range : Real;

        satisfy thrusterCountSatisfaction : thrusterCountRequirement by thrusters;

        doc /* Conflict resolution rationale: the requirement-defined thruster count is authoritative for implementation and verification, so the design multiplicity has been updated from [3] to [2]. */
    }
}

